#include <iostream>
#include <string>
#include <vector>
#include <sstream>
#include <functional>

// Function to capture stdout
std::string capture_stdout(std::function<void()> func) {
    std::stringstream ss;
    std::streambuf* old_cout = std::cout.rdbuf();
    std::cout.rdbuf(ss.rdbuf());
    func();
    std::cout.rdbuf(old_cout);
    return ss.str();
}

int main() {
    std::vector<std::pair<std::string, std::string>> test_cases = {
        {"1", "*\n"},
        {"3", "*\n**\n***\n"},
        {"5", "*\n**\n***\n****\n*****\n"},
        {"0", ""}, 
        {"-1", ""}
    };

    for (size_t i = 0; i < test_cases.size(); ++i) {
        std::string input = test_cases[i].first;
        std::string expected_output = test_cases[i].second;

        std::stringstream ss_in(input);
        std::streambuf* old_cin = std::cin.rdbuf();
        std::cin.rdbuf(ss_in.rdbuf());

        std::string actual_output = capture_stdout([]() {
            extern int user_main();
            user_main();
        });

        std::cin.rdbuf(old_cin);

        if (actual_output == expected_output) {
            // std::cout << "Test Case " << i + 1 << " Passed.\n";
        } else {
            std::cout << "Test Case " << i + 1 << " Failed!\n";
            std::cout << "Input: \"" << input << "\"\n";
            std::cout << "Expected:\n\"" << expected_output << "\"\n";
            std::cout << "Actual:\n\"" << actual_output << "\"\n";
            return 1;
        }
    }
    // std::cout << "All test cases passed.\n";
    return 0;
}
